class Resuscitation{constructor(t){this._model=t,this._comp_counter=0,this._resp_counter=0,this.p_max=60,this.p_min=0,this.f_comp=2,this.f_resp=.5,this.ratio_comp=3,this.ratio_resp=1,this.AA_pres_1=10}modelStep(){this.is_enabled&&this.modelCycle()}modelCycle(){let t=(this.p_max-this.p_min)/2,s=(this.p_max+this.p_min)/2,e=2*Math.PI*this.f_comp,o=t+s*Math.sin(e*this._comp_counter-.5*Math.PI);this.compressions=o,this._model.components["AA"].pres_ext=.8*o,this._model.components["AARCH"].pres_ext=.8*o,this._model.components["VCII"].pres_ext=.8*o,this._model.components["APC"].pres_ext=.8*o,this._model.components["LL"].pres_ext=.8*o,this._model.components["LR"].pres_ext=.8*o,this._model.components["PV"].pres_ext=.8*o,this._model.components["LA"].pres_ext=1*o,this._model.components["RA"].pres_ext=1*o,this._model.components["LV"].pres_ext=1*o,this._model.components["RV"].pres_ext=1*o,this._comp_counter+=this._model.modeling_stepsize,this._comp_counter>.5&&(this._comp_counter=0,this._model.components.ECG.ncc_ventricular=0)}}